# Store sessions with MFA status
user_sessions = {}

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Not authenticated'}), 401
        return f(*args, **kwargs)
    return decorated_function

def mfa_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Not authenticated'}), 401
        
        username = session['username']
        session_id = session.get('session_id')
        
        if session_id not in user_sessions or not user_sessions[session_id].get('mfa_verified'):
            return jsonify({'error': 'MFA verification required'}), 403
        
        return f(*args, **kwargs)
    return decorated_function

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username in users_db:
        return jsonify({'error': 'User already exists'}), 400
    
    mfa_secret = pyotp.random_base32()
    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_secret': mfa_secret,
        'mfa_verified': False
    }
    
    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(username, issuer_name='MyApp')
    
    return jsonify({
        'message': 'User registered successfully',
        'mfa_secret': mfa_secret,
        'provisioning_uri': provisioning_uri
    }), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session_id = secrets.token_hex(32)
    session['username'] = username
    session['session_id'] = session_id
    session['login_time'] = datetime.now().isoformat()
    
    user_sessions[session_id] = {
        'username': username,
        'mfa_verified': False,
        'login_time': datetime.now(),
        'mfa_deadline': datetime.now() + timedelta(minutes=5)
    }
    
    return jsonify({
        'message': 'Login successful',
        'redirect': '/verify-mfa',
        'session_id': session_id
    }), 200

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    if 'username' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    data = request.get_json()
    mfa_code = data.get('mfa_code')
    username = session['username']
    session_id = session.get('session_id')
    
    if not mfa_code:
        return jsonify({'error': 'MFA code required'}), 400
    
    user = users_db.get(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    totp = pyotp.TOTP(user['mfa_secret'])
    
    if totp.verify(mfa_code, valid_window=1):
        if session_id in user_sessions:
            user_sessions[session_id]['mfa_verified'] = True
            user_sessions[session_id]['mfa_verified_time'] = datetime.now()
        
        users_db[username]['mfa_verified'] = True
        
        return jsonify({
            'message': 'MFA verification successful',
            'access_granted': True
        }), 200
    else:
        return jsonify({'error': 'Invalid MFA code'}), 401

