@app.route('/mfa-status', methods=['GET'])
@login_required
def mfa_status():
    session_id = session.get('session_id')
    
    if session_id not in user_sessions:
        return jsonify({'error': 'Session not found'}), 404
    
    session_data = user_sessions[session_id]
    mfa_verified = session_data.get('mfa_verified', False)
    
    response = {
        'mfa_verified': mfa_verified,
        'username': session_data['username']
    }
    
    if not mfa_verified:
        deadline = session_data.get('mfa_deadline')
        if deadline:
            response['mfa_deadline'] = deadline.isoformat()
            response['time_remaining'] = max(0, int((deadline - datetime.now()).total_seconds()))
    
    return jsonify(response), 200

@app.route('/logout', methods=['POST'])
def logout():
    session_id = session.get('session_id')
    if session_id in user_sessions:
        del user_sessions[session_id]
    
    session.clear()
    return jsonify({'message': 'Logged out successfully'}), 200

